dupli_data.duplicated()

"""`drop_duplicates`メソッドを使うと，重複したデータを削除した結果のデータが返される．"""

# 重複削除
dupli_data.drop_duplicates()

"""次に**マッピング処理**を説明する．共通のキーとなるデータに対して，一方の(参照)テーブルからそのキーに対応するデータを引っ張ってくる機能である．以下の例は，都道府県名と地域名を対応付けた参照データである．"""

# 参照データ
city_map = {
    'Tokyo': 'Kanto',
    'Hokkaido': 'Hokkaido',
    'Osaka': 'Kansai',
    'Kyoto': 'Kansai'
}

city_map

"""そして，`df1`の`city`カラムをベースとして，上の参照データ`city_map`から対応する地域名データを持ってきて，新しく一番右に`region`というカラムとして追加する．"""

# 参照データを結合
# もし対応するデータがなかったら，NaNになる
df1['region'] = df1['city'].map(city_map)

df1

"""次に，ある離散的な範囲にデータを分割して集計する機能である**ビン分割**について説明する．例えば，上のデータに対して，5年区切りで集計したい場合など，ある特定の分割をして計算をするときに使う．

以下のように，1980, 1985, 1990, 1995, 2000のように5年単位でビン分割するためのリストを用意し，Pandasの`cut`関数を使うと，そのように分割できる．`cut`関数では，１つめの引数に分割するデータ，２つめの引数に分割する境界値を指定する．
"""

# 分割の粒度
birth_year_bins = [1980, 1985, 1990, 1995, 2000]

# ビン分割の実施
birth_year_cut_data = pd.cut(df1.birth_year, birth_year_bins)
birth_year_cut_data

"""上記の結果を使ってそれぞれの数を集計したい場合は，`value_counts`関数を使う．"""

# 集計結果
pd.value_counts(birth_year_cut_data)

"""上記では，分割リストを用意したが，あらかじめ分割数を指定したい場合は，以下のようにする．"""

# 2分割
pd.cut(df1.birth_year, 2)

"""また，`qcut`関数を使うと，分位点での分割もできる．"""

pd.value_counts(pd.qcut(df1.birth_year, 2))

"""### 3.4. データの集約とグループ演算
***
ここでは，あるカラムを軸にして集計する処理を学ぶ．

`groupby`メソッドを使うことで，ある変数を軸としてその単位で集計処理をする．以下の`df1`を対象に，集約やグループ演算を行っていく．
"""

df1

"""以下のように`groupby`メソッドでグループ化してから`size`メソッドを使うと，それぞれの`city`の値がいくつあるのか計算できる．"""

# サイズ情報
df1.groupby('city').size()

"""`city`を軸として，`birth_year`の平均値を算出する方法は以下の通りである．"""

# cityを軸としてbirth_yearの平均値の算出
df1.groupby('city')['birth_year'].mean()

"""以下のように，軸を複数設定することもできる．"""

# regionとcityを2軸として，birth_yearの平均値を求める
df1.groupby(['region', 'city'])['birth_year'].mean()

"""また，`groupby`メソッドに`as_index = False`を設定すると，そのままテーブルとして扱うことができる．"""

# テーブル
df1.groupby(['region', 'city'], as_index=False)['birth_year'].mean()

"""### 3.5. 欠損値の取り扱い
***
データを扱っていると，欠損しているデータや異常値データが多く存在する．ここでは，欠損値の判定や扱い方について学ぶ．

データの欠損は，入力忘れ・無回答・システム上の問題など様々な原因が考えられるため，適切な扱い方が必要となる．

ここでは，以下のようなデータを例として扱い，以前記述した欠損値の扱い方の具体例について詳しく見ていく．値を`NaN`(`NA`)にした部分が欠損値であるとする．
"""

from numpy import nan as NA

# データの準備
df = pd.DataFrame(np.random.rand(10, 4))

# NAにする
df.iloc[1, 0] = NA
df.iloc[2:3, 2] = NA
df.iloc[5:, 3] = NA

df

"""#### リストワイズ削除
***
`dropna`メソッドを用いて，`NaN`がある行を全て取り除く手法．
"""

df.dropna()

"""#### ペアワイズ削除
***
欠損している列のデータを無視して，利用可能なデータのみを使う方法．使いたい列を取り出してから`dropna`メソッドを適用する．
"""

df[[0, 1]].dropna()

"""#### fillnaで埋める
***
`fillna(値)`で，`NaN`になっている箇所をある値で埋める方法．以下は，`NaN`を`0`として扱うケースである．
"""

df.fillna(0)

"""#### 前の値で埋める
***
`ffill`メソッドで，直前の行の値で埋める手法．この処理は金融の時系列データの処理などで扱うことができる．
"""

df.fillna(method = 'ffill')

"""#### 平均値で埋める
***
`mean`メソッドを使用して，平均値で埋める方法．**平均値代入法**という．
"""

df.fillna(df.mean())

"""### 3.6. 時系列データの取り扱い
***
最後にPandasを使った時系列データの取り扱いについて学ぶ．ここでは，サンプルとして為替の時系列データを扱う．
"""

# ライブラリのインポート
import pandas_datareader.data as pdr

"""はじめに，サンプルデータに含まれる`2010/1/4`から`2019/12/30`までのドル円の為替レートデータ(`DEXJPUS`)は以下のように表示できる．"""

start_date = '2010/1/4'
end_date = '2019/12/30'

fx_jpusdata = pdr.DataReader('DEXJPUS', 'fred', start_date, end_date)

fx_jpusdata.head()

"""上記のデータから年や日にちを抽出する際は，`resample`メソッドと`last`メソッドを用いる．以下の例は，`resample('D')`で日付を取り出し，`last`で末尾のデータ(つまり，一日ごと)を取り出している．`resample`の引数で`M`を指定すると**月**，`Y`を指定すると**年**を取り出すことができる．"""

fx_jpusdata.resample('D').last().head(10)

"""上の出力を見ると欠損値があることがわかる．前節で学んだ方法である，前の日の値で埋める処理をする．"""

fx_jpusdata.resample('D').ffill().head(10)

"""次に，前日とのレートを比較したい場合を考える．上の例だと，「2010-01-04 の 92.55」と「2010-01-05 の 91.48」であり，その比率を計算することができるが，それを全ての日付について適応させる処理をする．

`shift`メソッドを使うことで，インデックスは固定したまま，データだけをずらすことができる．以下はデータを1つあとにずらしており，「2010-01-04 の 92.55」を「2010-01-05」として扱われるようになる．
"""

fx_jpusdata_ratio = fx_jpusdata / fx_jpusdata.shift(1)
fx_jpusdata_ratio.head()

"""最後に，時系列データでよく使われる**移動平均**の処理方法を見ていく．

さきほど扱った`fx_jpusdata`について，3日間の移動平均線を作成することを考える．Pandasの`rolling`メソッドで引数分のデータを扱うことができ，`mean`メソッドで平均を計算している．
"""

fx_jpusdata.rolling(3).mean().head()

